class Solution {
    public boolean doesAliceWin(String s) {
        int countOddVowels = countVowels(s, 1);
        int countEvenVowels = countVowels(s, 0);
        return countOddVowels > countEvenVowels;
    }

    public int countVowels(String s, int oddVowelCount) {
        int count = 0;
        for (int i = 0; i < s.length(); i++) {
            if (isVowel(s.charAt(i)) {
                if (oddVowelCount == 0) {
                    return count;
                }
                count++;
                oddVowelCount--;
            }
        }
        return count;
    }

    public boolean isVowel(char c) {
        return c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u';
    }
}
